<template><view class="page"><xy-header title="门店信息"/><view class="wrap"><view v-for="store in stores" :key="store.storeId" class="card"><text class="name">{{store.storeName}}</text><text>{{store.address}}</text><text>营业时间：{{store.businessHours}}</text><view class="actions"><button @click="call(store.phone)">拨打电话</button><button :disabled="!store.latitude||!store.longitude" @click="nav(store)">地图导航</button></view></view><view v-if="!stores.length" class="empty">暂无营业门店</view></view></view></template>
<script>import{publicRequest,showRequestError}from'../../utils/api';export default{data(){return{stores:[]}},onLoad(){this.load()},methods:{async load(){try{this.stores=await publicRequest({url:'/app/stores'})}catch(e){showRequestError(e)}},call(phone){uni.makePhoneCall({phoneNumber:phone})},nav(store){uni.openLocation({latitude:Number(store.latitude),longitude:Number(store.longitude),name:store.storeName,address:store.address})}}}</script><style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:24rpx}.card{display:flex;flex-direction:column;gap:16rpx;margin-bottom:18rpx;padding:30rpx;border-radius:22rpx;background:#fff}.name{font-size:34rpx;font-weight:700}.actions{display:flex;gap:18rpx}.actions button{flex:1}.empty{padding:120rpx;text-align:center;color:var(--xy-muted)}</style>
